class Solution:
    def waysToSplitArray(self, nums):
        n = len(nums)
        cnt = 0
        for i in range(n - 1):
            left = sum(nums[:i + 1])
            right = sum(nums[i + 1:])
            if left >= right:
                cnt += 1
        return cnt

solutions.python:
class Solution:
    def waysToSplitArray(self, nums):
        total = sum(nums)
        left = 0
        cnt = 0
        for i in range(len(nums) - 1):
            left += nums[i]
            if left >= total - left:
                cnt += 1
        return cnt

