var waysToSplitArray = function(nums) {
    let total = 0;
    for (const x of nums) total += x;
    let left = 0, cnt = 0;
    for (let i = 0; i < nums.length - 1; i++) {
        left += nums[i];
        if (left >= total - left) cnt++;
    }
    return cnt;
};
